svg.script:

let currentMode = 'rotary';
let lastTime = 0;

// Physics Simulation States
let currentLift = 0;
let altitude = 0;
let verticalVelocity = 0;

// Animation States
let rotorAngle = 0;
let windOffset = 0;

// Custom SVG Sliders State
const SLIDER_WIDTH = 310;
let activeSlider = null;

const sliders = {
    'rot-speed': { min: 0, max: 100, val: 20 },
    'rot-pitch': { min: 0, max: 20, val: 5 },
    'fix-speed': { min: 0, max: 150, val: 30 },
    'fix-aoa':   { min: 0, max: 25, val: 4 }
};

// Constants
const LIFT_REQUIRED_TO_FLY = 5000;
const MAX_LIFT_PIXELS = 250;
const BASE_Y = 530;
const MAX_ALTITUDE = 230;

function initSimulation() {
    setMode('rotary');
    requestAnimationFrame(animationLoop);
}

// Pointer coordinate extraction (mouse or touch)
function getClientX(evt) {
    if (evt.touches && evt.touches.length > 0) {
        return evt.touches[0].clientX;
    }
    if (evt.changedTouches && evt.changedTouches.length > 0) {
        return evt.changedTouches[0].clientX;
    }
    return evt.clientX;
}

function getClientY(evt) {
    if (evt.touches && evt.touches.length > 0) {
        return evt.touches[0].clientY;
    }
    if (evt.changedTouches && evt.changedTouches.length > 0) {
        return evt.changedTouches[0].clientY;
    }
    return evt.clientY;
}

// Custom Slider Drag Handling
function startDrag(evt, id) {
    activeSlider = id;
    updateDrag(evt);
}

function startDragTouch(evt, id) {
    evt.preventDefault();
    activeSlider = id;
    updateDrag(evt);
}

function onMouseMove(evt) {
    if (activeSlider) {
        updateDrag(evt);
    }
}

function onMouseUp(evt) {
    activeSlider = null;
}

function onTouchMove(evt) {
    if (activeSlider) {
        evt.preventDefault();
        updateDrag(evt);
    }
}

function onTouchEnd(evt) {
    activeSlider = null;
}

function updateDrag(evt) {
    if (!activeSlider) return;

    // Map screen pointer position exactly to SVG coordinate space
    const svg = document.getElementById('main-svg');
    const pt = svg.createSVGPoint();
    pt.x = getClientX(evt);
    pt.y = getClientY(evt);
    const svgP = pt.matrixTransform(svg.getScreenCTM().inverse());

    // The sliders track horizontally starting at x=810
    let localX = svgP.x - 810;
    if (localX < 0) localX = 0;
    if (localX > SLIDER_WIDTH) localX = SLIDER_WIDTH;

    // Update Data Value
    const s = sliders[activeSlider];
    s.val = s.min + (localX / SLIDER_WIDTH) * (s.max - s.min);

    // Update Visual Slider Track & Thumb
    document.getElementById('track-' + activeSlider).setAttribute('x2', localX);
    document.getElementById('thumb-' + activeSlider).setAttribute('cx', localX);

    updateSim();
}

function setMode(mode) {
    currentMode = mode;

    // Reset Flight Physics
    altitude = 0;
    verticalVelocity = 0;
    document.getElementById('heli-model').setAttribute('transform', `translate(0, 0)`);
    document.getElementById('plane-model').setAttribute('transform', `translate(0, 0)`);
    document.getElementById('force-vectors').setAttribute('transform', `translate(0, 0)`);

    // Toggle SVG Views
    document.getElementById('view-rotary').style.display = (mode === 'rotary') ? 'block' : 'none';
    document.getElementById('view-fixed').style.display = (mode === 'fixed') ? 'block' : 'none';

    // Toggle SVG Controls
    document.getElementById('ctrl-rotary').setAttribute('display', (mode === 'rotary') ? 'block' : 'none');
    document.getElementById('ctrl-fixed').setAttribute('display', (mode === 'fixed') ? 'block' : 'none');

    // Update Tab Styling
    if (mode === 'rotary') {
        document.getElementById('tab-rotary').classList.add('active');
        document.getElementById('tab-fixed').classList.remove('active');

        document.getElementById('info-title').textContent = 'Rotary Wing Flight';
        document.getElementById('info-badge').style.backgroundColor = '#e11d48';
        document.getElementById('info-desc').innerHTML = 'Generates lift by actively spinning blades (airfoils) through the air using an engine. <strong>Because the blades create their own relative wind, the aircraft does not need to move forward to fly.</strong> This allows for vertical takeoff, landing, and hovering. Lift is controlled by adjusting the rotor RPM and the collective pitch (angle) of all blades simultaneously.';
    } else {
        document.getElementById('tab-fixed').classList.add('active');
        document.getElementById('tab-rotary').classList.remove('active');

        document.getElementById('info-title').textContent = 'Fixed Wing Flight';
        document.getElementById('info-badge').style.backgroundColor = '#38bdf8';
        document.getElementById('info-desc').innerHTML = 'Generates lift by forcing the entire aircraft forward through the air. <strong>It relies entirely on forward velocity (airspeed) to push air over the stationary wings.</strong> This makes it highly efficient for speed and long-distance travel, but requires a runway. Lift is controlled by engine thrust (speed) and tilting the nose up/down (Angle of Attack).';
    }

    updateSim();
}

function updateSim() {
    let liftForce = 0;

    if (currentMode === 'rotary') {
        const speed = sliders['rot-speed'].val;
        const pitch = sliders['rot-pitch'].val;

        document.getElementById('val-rot-speed').textContent = Math.round(speed) + '%';
        document.getElementById('val-rot-pitch').textContent = Math.round(pitch) + '°';

        // Physics calculation
        const speedFactor = speed / 100;
        liftForce = speedFactor * speedFactor * (pitch / 20) * 12000;

        // Visual update
        document.getElementById('rotary-pitch-visual').setAttribute('transform', `rotate(${-pitch}, 10, 30)`);

    } else {
        const speed = sliders['fix-speed'].val;
        const aoa = sliders['fix-aoa'].val;

        document.getElementById('val-fix-speed').textContent = Math.round(speed) + ' kts';
        document.getElementById('val-fix-aoa').textContent = Math.round(aoa) + '°';

        // Physics calculation
        const speedFactor = speed / 150;

        // Stall condition: if AoA is too high (> 20), lift drops
        let stallPenalty = 1;
        if (aoa > 20) {
            stallPenalty = Math.max(0.1, 1 - ((aoa - 20) * 0.2)); 
        }

        liftForce = speedFactor * speedFactor * (aoa / 25) * 15000 * stallPenalty;

        // Visual update
        document.getElementById('fixed-pitch-visual').setAttribute('transform', `rotate(${-aoa}, 50, 0)`);
    }

    // Set global current lift to be picked up by the animation loop
    currentLift = liftForce;

    // Update the Lift Arrow visually
    const liftPixelLength = Math.min(MAX_LIFT_PIXELS, (liftForce / LIFT_REQUIRED_TO_FLY) * 150);
    const arrowTipY = BASE_Y - Math.max(5, liftPixelLength);

    document.getElementById('lift-arrow').setAttribute('y2', arrowTipY);
    document.getElementById('lift-text').setAttribute('y', arrowTipY - 15);
    document.getElementById('lift-value').textContent = Math.round(liftForce);
}

// 60fps Animation Loop & Physics Integration
function animationLoop(timestamp) {
    if (!lastTime) lastTime = timestamp;
    const dt = timestamp - lastTime || 16;
    lastTime = timestamp;

    // --- PHYSICS ENGINE: ALTITUDE ACCELERATION ---
    const netLift = currentLift - LIFT_REQUIRED_TO_FLY;

    // Calculate acceleration (proportional to net lift force)
    const accel = netLift * 0.0005; 

    verticalVelocity += accel * (dt / 16);
    verticalVelocity *= 0.92; // Air resistance / Damping

    altitude += verticalVelocity * (dt / 16);

    // Floor Clamp
    if (altitude < 0) {
        altitude = 0;
        verticalVelocity = 0;
    }

    // Ceiling Clamp
    if (altitude > MAX_ALTITUDE) {
        altitude = MAX_ALTITUDE;
        verticalVelocity = 0;
    }

    // Apply Altitude Translation to the elements
    document.getElementById('heli-model').setAttribute('transform', `translate(0, ${-altitude})`);
    document.getElementById('plane-model').setAttribute('transform', `translate(0, ${-altitude})`);
    document.getElementById('force-vectors').setAttribute('transform', `translate(0, ${-altitude})`);

    // Update the flight status text dynamically based on the physics
    const statusText = document.getElementById('flight-status');
    if (currentMode === 'fixed' && sliders['fix-aoa'].val > 20) {
        statusText.textContent = "STALL WARNING";
        statusText.setAttribute("fill", "#ef4444");
    } else if (altitude <= 0.1 && netLift <= 0) {
        statusText.textContent = "GROUNDED";
        statusText.setAttribute("fill", "#cbd5e1");
    } else if (verticalVelocity > 0.5) {
        statusText.textContent = "CLIMBING";
        statusText.setAttribute("fill", "#10b981");
    } else if (verticalVelocity < -0.5) {
        statusText.textContent = "DESCENDING";
        statusText.setAttribute("fill", "#f59e0b");
    } else {
        statusText.textContent = currentMode === 'rotary' ? "HOVERING" : "LEVEL FLIGHT";
        statusText.setAttribute("fill", "#38bdf8");
    }

    // --- VISUAL ANIMATIONS ---
    if (currentMode === 'rotary') {
        const speed = sliders['rot-speed'].val;
        const rotationDelta = (speed * 0.4) + 0.5; 
        rotorAngle = (rotorAngle + rotationDelta) % 360;
        document.getElementById('rotor-spin').setAttribute('transform', `rotate(${rotorAngle})`);
    } else {
        const speed = sliders['fix-speed'].val;
        const windDelta = speed * 0.15;
        windOffset -= windDelta;
        const windLines = document.getElementsByClassName('wind-line');
        for (let i = 0; i < windLines.length; i++) {
            windLines[i].setAttribute('stroke-dashoffset', windOffset);
        }
    }

    requestAnimationFrame(animationLoop);
}
